const company = $.input.companyName;
const industry = $.input.industry || '';
const ctx = industry ? ' ' + industry : '';

return {
  companyQuery: company + ctx + ' company overview about funding team',
  newsQuery: company + ' latest news announcements ' + new Date().getFullYear(),
  company,
  industry: industry || 'N/A',
  today: new Date().toISOString().split('T')[0]
};

const results = $.steps.searchCompany.response.results || $.steps.searchCompany.response.data || [];
let topUrl = '';
for (const r of results) {
  const url = r.url || '';
  if (url && (url.includes($.input.companyName.toLowerCase().replace(/\s+/g, '')) || !topUrl)) {
    topUrl = url;
    break;
  }
}
if (!topUrl && results.length > 0) topUrl = results[0].url || '';
return { topUrl, hasUrl: !!topUrl };

let compiled = '';

const companyResults = $.steps.searchCompany.response.results || $.steps.searchCompany.response.data || [];
compiled += '=== COMPANY OVERVIEW ===\n';
companyResults.slice(0, 5).forEach((r, i) => {
  compiled += 'Source ' + (i + 1) + ': ' + (r.title || 'N/A') + '\n';
  compiled += (r.text || r.content || '').slice(0, 1500) + '\n\n';
});

const newsResults = $.steps.searchNews.response.results || $.steps.searchNews.response.data || [];
compiled += '=== RECENT NEWS ===\n';
newsResults.slice(0, 5).forEach((r, i) => {
  compiled += 'News ' + (i + 1) + ': ' + (r.title || 'N/A') + '\n';
  compiled += (r.text || r.content || '').slice(0, 1000) + '\n\n';
});

const scrapeResp = $.steps.scrapeCompanySite && $.steps.scrapeCompanySite.response;
if (scrapeResp) {
  const md = (scrapeResp.data && scrapeResp.data.markdown) || scrapeResp.markdown || '';
  if (md) {
    compiled += '=== COMPANY WEBSITE (SCRAPED) ===\n';
    compiled += md.slice(0, 3000) + '\n\n';
  }
}

return { compiled, sourceCount: companyResults.length + newsResults.length };

const d = $.steps.compileResearch.output;
const q = $.steps.buildQueries.output;

let prompt = 'You are a senior sales intelligence analyst. Create a comprehensive sales brief for prospecting ' + q.company + ' (Industry: ' + q.industry + ').\n\n';
prompt += 'RESEARCH DATA:\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Build a complete company profile useful for a sales team\n';
prompt += '- Identify potential pain points and business challenges\n';
prompt += '- Suggest personalized outreach angles and talking points\n';
prompt += '- Identify key decision makers (titles/roles if available)\n';
prompt += '- Note recent events that could be conversation starters\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "company": "' + q.company + '",\n';
prompt += '  "industry": "industry",\n';
prompt += '  "overview": "2-3 sentence company description",\n';
prompt += '  "founded": "year or N/A",\n';
prompt += '  "headquarters": "location",\n';
prompt += '  "employeeCount": "estimated",\n';
prompt += '  "funding": "funding info or N/A",\n';
prompt += '  "keyProducts": ["product 1", "product 2"],\n';
prompt += '  "targetBuyers": [{ "title": "VP of Engineering", "relevance": "why they matter" }],\n';
prompt += '  "painPoints": ["pain point 1", "pain point 2"],\n';
prompt += '  "talkingPoints": ["personalized angle 1", "angle 2"],\n';
prompt += '  "recentNews": [{ "headline": "title", "relevance": "why it matters for outreach" }],\n';
prompt += '  "competitors": ["competitor 1"],\n';
prompt += '  "techStack": ["known tools"],\n';
prompt += '  "outreachStrategy": "recommended approach",\n';
prompt += '  "summary": "executive summary for the sales team"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { company: $.input.companyName, overview: raw, painPoints: [], talkingPoints: [], recentNews: [], summary: raw }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().split('T')[0];

const headerRow = ['Company', 'Industry', 'Overview', 'HQ', 'Employees', 'Funding', 'Key Products', 'Pain Points', 'Talking Points', 'Competitors', 'Tech Stack', 'Outreach Strategy', 'Recent News', 'Date Researched'];
const dataRow = [
  ai.company || '',
  ai.industry || '',
  ai.overview || '',
  ai.headquarters || '',
  ai.employeeCount || '',
  ai.funding || '',
  (ai.keyProducts || []).join(', '),
  (ai.painPoints || []).join('; '),
  (ai.talkingPoints || []).join('; '),
  (ai.competitors || []).join(', '),
  (ai.techStack || []).join(', '),
  ai.outreachStrategy || '',
  (ai.recentNews || []).map(n => n.headline || n).join('; '),
  today
];

return { rows: [headerRow, dataRow], summary: ai.summary || '' };
